  ('艺圃', 1, 'Shilun Hall', '世纶堂', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_02.jpg'),
