  ('艺圃', 6, 'Chaoshuang Pavilion', '朝爽亭', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_07.png'),
  ('艺圃', 7, 'Bilang Pavilion', '碧浪亭', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_08.jpg'),
  ('艺圃', 8, 'Qinlu Hermitage', '芹庐', '<p>water dropwort) comes from the Book of Odes: "By the joyful waters of Pan, I gather the water celery." Since ancient times, "offering celery" has been a scholar''s humble metaphor — the gift may be meager, but the sincerity is genuine. Naming this retreat "Qinlu" reveals the garden owner''s contentment with simplicity and his celebration of the unadorned. Within the courtyard stand a few stalks of bamboo, an old plum tree, and one or two scholar''s rocks set against whitewashed walls — a natural literati painting. Though tiny, the courtyard embodies the Buddhist principle of "a mustard seed holding Mount Sumeru" — the universe within a square inch. This was the owner''s retreat for reading and meditation, and even today, far from the flow of visitors in the main garden, it retains the purest breath of antiquity.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_09.jpg'),
  ('艺圃', 9, 'Boya Hall', '博雅堂', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_10.jpg'),
  ('周庄古镇', 0, 'Ancient Stage', '古戏台', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_01.jpg'),
  ('周庄古镇', 1, 'Twin Bridges', '双桥', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_02.jpg'),
  ('周庄古镇', 2, 'Shen Hall', '沈厅', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_03.jpg'),
  ('周庄古镇', 3, 'Zhang Hall', '张厅', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_04.jpg'),
  ('周庄古镇', 4, 'Fu''an Bridge', '富安桥', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_05.png'),
  ('周庄古镇', 5, 'Milou (Labyrinth Tower)', '迷楼', '<p>bewitched) conveys both the intoxication of wine and the poets'' bewilderment and lament over the turbulent times. The interior is small, with a steep, narrow wooden staircase; the second floor has windows overlooking the canal. Today, Milou displays reproductions of the Southern Society poets'' biographies and handwritten works, recreating the spiritual world of early Republican-era Jiangnan literati who expressed their patriotism and sorrow through wine and verse. Though not the largest attraction in Zhouzhuang, its literary depth makes it a must-visit for lovers of literature and history.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_06.jpg'),
  ('周庄古镇', 6, 'Zhouzhuang Museum', '周庄博物馆', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_07.jpg'),
  ('周庄古镇', 7, 'Guailou (Strange Tower)', '怪楼', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_08.jpg'),
  ('周庄古镇', 8, 'Zhenfeng Bridge', '贞丰桥', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_09.png'),
  ('周庄古镇', 9, 'Quanfu Temple', '全福讲寺', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_10.jpg'),
  ('拙政园', 0, 'Lanxue Hall (Hall of Orchid and Snow)', '兰雪堂', '<p>Lanxue Hall is the main entrance hall of the Humble Administrator''s Garden, a three-bay structure with a rigid gable roof. Its name comes from Li Bai''s verse "Standing alone between heaven and earth, a fresh breeze scatters orchids and snow," reflecting the garden owner''s lofty aspirations and integrity. In front of the hall stands a large lacquer carving of the full garden panorama. Inside, the decor is restrained and refined, with a painting of pines and bamboo hanging in the central hall and a couplet extolling both natural beauty and scholarly pursuits — setting the tone for the entire literati garden.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_01.jpg'),
  ('拙政园', 1, 'Yuanxiang Hall (Hall of Distant Fragrance)', '远香堂', '<p>Yuanxiang Hall is the architectural centerpiece of the garden''s middle section, a three-bay hall raised on a bluestone platform. Its name draws from Zhou Dunyi''s famous essay "On Loving the Lotus" — "the farther the fragrance travels, the purer it becomes" — subtly expressing the owner''s self-identification with the lotus''s noble character. With floor-to-ceiling latticed windows on all four sides and no solid walls, the hall offers uninterrupted views in every direction: northward to the Snow-Fragrant Cloud-Like Pavilion, southward to the yellowstone rockery and magnolia, westward to the Lotus Breeze Pavilion, and eastward to the Embroidered Silk Pavilion. It is a masterclass in the Chinese garden techniques of "framed views" and "borrowed scenery."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_02.jpg'),
  ('拙政园', 2, 'Xiangzhou (Fragrant Isle)', '香洲', '<p>Xiangzhou is one of the garden''s most distinctive structures, ingeniously combining four architectural forms into a single composition: a stone-paved platform at the bow, a covered corridor as the cabin, and a two-story tower at the stern — creating the illusion of an ornate pleasure boat moored by the water. The name "Fragrant Isle" evokes a lush, grassy islet. A plaque inscribed by the Ming master Wen Zhengming hangs at the bow, while the upper level, named "Chengguan Tower" (Tower of Clear Contemplation), offers sweeping views across shimmering garden waters. This is a quintessential example of the "dry boat" motif in classical Chinese gardens, brilliantly merging water-town imagery with garden architecture.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_03.jpg'),
  ('拙政园', 3, 'Hefeng Simian Pavilion (Lotus Breeze from All Sides Pavilion)', '荷风四面亭', '<p>Hefeng Simian Pavilion is a delicate hexagonal pavilion with a pointed roof, built on a rocky islet at the center of the garden''s main pond and connected to both shores by winding bridges. Its name, borrowed from Tang poet Meng Haoran''s line "the lotus breeze bears its fragrance," perfectly captures its poetic essence. In midsummer, when lotus blooms carpet the surrounding water and a gentle breeze carries their scent from all four sides, one feels as though standing inside a painting. The couplet on its pillars — "Lotus blossoms on four sides, willows on three; half a pool of autumn water, a mountain in one room" — elegantly evokes the changing seasons. Beyond being an exquisite lotus-viewing perch, this pavilion is the compositional linchpin of the garden''s waterscape, skillfully linking Yuanxiang Hall, Xiangzhou, and Jianshan Tower.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_04.jpg'),
  ('拙政园', 4, 'Xiaofeihong (Little Flying Rainbow)', '小飞虹', '<p>Xiaofeihong is a supremely poetic covered bridge and the only surviving example of its kind among Suzhou''s classical gardens. The three-span bridge features vermilion balustrades beneath a full-length roof, with green water flowing gently beneath. Its name, drawn from Bao Zhao''s verse "a flying rainbow gazes upon the Qin River," likens the bridge''s graceful arc to a rainbow. Connecting Yiyu Pavilion on one end to Dezhi Pavilion on the other, the bridge casts its reflection onto the water, blurring the line between reality and illusion. Viewed from Yuanxiang Hall, Xiaofeihong appears as a crimson arc suspended above the water, forming a richly layered composition with the pavilions, rockeries, and foliage beyond — a brilliant demonstration of "borrowed" and "divided" scenic techniques.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_05.jpg'),
  ('拙政园', 5, 'Jianshan Tower (Tower of Seeing the Mountain)', '见山楼', '<p>Jianshan Tower is the tallest structure in the garden, a two-story double-eaved building with a hip-and-gable roof standing on the northern shore of the garden''s main pond. Its name echoes Tao Yuanming''s famous lines "Picking chrysanthemums by the eastern hedge, I gaze in leisure upon the southern mountain," expressing the owner''s longing for a life of reclusion amid nature. The open-sided ground floor serves as a cool hall for watching fish and lotus, while the upper study commands a view that frames Suzhou''s iconic North Temple Pagoda — the supreme achievement of the Chinese garden technique of "borrowed scenery," pulling a city landmark into the garden''s visual field and vastly expanding its perceived depth. The waterfront terrace in front is one of the best spots for panoramic photography.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_06.jpg'),
  ('拙政园', 6, 'Sanshiliu Yuanyang Guan (Thirty-Six Mandarin Duck Hall)', '卅六鸳鸯馆', '<p>Sanshiliu Yuanyang Guan is the principal building of the garden''s western section, originally named for the thirty-six pairs of mandarin ducks that once graced the pond before it. The hall follows the "mandarin duck hall" layout — two halls separated by a screen partition: the southern hall is warm in winter with abundant sunlight, while the northern hall stays cool in summer with cross-ventilation from the water, a brilliant demonstration of traditional architectural wisdom. Its most striking feature is the stained-glass lattice windows on all four sides — blue-and-white diamond-patterned panes that refract dreamlike light and shadow, a rarity in classical Chinese gardens and a precious trace of Western influence during the late Qing period. The owner Zhang Luqian once entertained guests and enjoyed Kunqu opera here, and the hall''s exquisite wood carvings, plaques, and couplets still whisper of literati refinement.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_07.jpg'),
  ('拙政园', 7, 'Yushei Tongzuo Pavilion (With Whom Shall I Sit Pavilion)', '与谁同坐轩', '<p>Yushei Tongzuo Pavilion is one of the garden''s most inventive architectural designs: the pavilion is fan-shaped in plan — its roof, walls, doors, windows, stone table, stone stools, and even the hanging plaque are all in the form of a fan, an exquisite conceit. Its name comes from Su Shi''s celebrated verse "With whom shall I sit? The bright moon, the fresh breeze, and me" — a rhetorical question that conveys a transcendent detachment, a communion with the universe in splendid solitude. Perched at the southeastern corner of the western pond, with water on three sides and a covered corridor at its back, it faces Sanshiliu Yuanyang Guan across the water. This tiny fan-shaped space holds infinite poetry and philosophy, a perfect distillation of the classical Chinese garden aesthetic of "seeing the great in the small."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_08.jpg'),
  ('拙政园', 8, 'Liuting Ge (Pavilion for Lingering and Listening)', '留听阁', '<p>Liuting Ge is a small, elegantly understated waterside pavilion in the garden''s western section — a single-story structure with a hip-and-gable roof, surrounded by water on three sides in serene seclusion. Its name is taken from the late Tang poet Li Shangyin''s haunting line "Leave the withered lotus to listen to the sound of rain," a verse suffused with melancholy and depth. In autumn, when the lotus blooms have faded and only withered stalks remain, the patter of rain on dry lotus leaves creates a rustling, intimate music — a celebration of imperfect, quiet beauty that represents the highest expression of the traditional Chinese aesthetic of wabi-like poignancy. Leaning on the railing, one gazes upon clear pond waters, a distant pagoda silhouette, and nearby withered lotus whispering in the rain — a moment of transcendence where time dissolves and the self merges with the scene. Liuting Ge is not merely a viewpoint; it is a state of mind.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_09.jpg')
), mapped_rows AS (
  SELECT CONCAT(a.id, '_sa_', LPAD((i.sort_order + 1)::text, 2, '0')) AS id, a.id AS attraction_id, i.name_en, i.name_zh, i.body, i.cover_image_path, i.sort_order
  FROM input_rows i JOIN attractions a ON a.chinese_name = i.attraction_name_zh
)
INSERT INTO sub_areas (id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active)
SELECT id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, TRUE FROM mapped_rows
ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_zh=EXCLUDED.name_zh, body=EXCLUDED.body, cover_image_path=EXCLUDED.cover_image_path, sort_order=EXCLUDED.sort_order, is_active=EXCLUDED.is_active, updated_at=NOW();
